import React from "react";
import {
  View,
  Text,
  StyleSheet,
  Image,
  ImageBackground,
  TouchableOpacity,
  Platform,
  useWindowDimensions,
} from "react-native";

export default function HeroSection({ onOpenDemo }) {
  const { width } = useWindowDimensions();
  const isMobile = width < 768;

  return (
    <View style={styles.wrapper}>
      <ImageBackground
        source={require("../../../assets/hero_bg.png")}
        style={styles.bg}
        resizeMode="cover"
      >
        {/* Dark overlay */}
        <View style={styles.overlay} />

        {/* Soft vignette */}
        <View style={styles.vignetteTop} />
        <View style={styles.vignetteBottom} />

        {/* Header row (logo left, language right) */}
        <View style={styles.topBar}>
          <View style={styles.logoRow}>
            <Image
              source={require("../../../assets/cinebridge_logo.png")}
              style={styles.logo}
              resizeMode="contain"
            />
          </View>

          <TouchableOpacity activeOpacity={0.85} style={styles.langBtn}>
            <Text style={styles.langIcon}>🌐</Text>
            <Text style={styles.langText}>English</Text>
            <Text style={styles.langCaret}>▾</Text>
          </TouchableOpacity>
        </View>

        {/* Center content */}
        <View style={[styles.content, { paddingHorizontal: isMobile ? 18 : 24 }]}>
          <Text style={[styles.kicker, { fontSize: isMobile ? 18 : 22 }]}>
            African films. Licensed for public screening.
          </Text>

          <Text style={[styles.headline, { fontSize: isMobile ? 44 : 64 }]}>
            Pay once. <Text style={styles.headlineAccent}>Screen once.</Text>
          </Text>

          <Text style={[styles.sub, { fontSize: isMobile ? 16 : 18 }]}>
            Built for cinemas, bars, schools and cultural spaces — not for streaming.
          </Text>

          <TouchableOpacity
            activeOpacity={0.9}
            onPress={onOpenDemo}
            style={[styles.cta, isMobile && { width: "100%" }]}
          >
            <View style={styles.playCircle}>
              <Text style={styles.playIcon}>▶</Text>
            </View>
            <Text style={styles.ctaText}>Download Demo Film</Text>
          </TouchableOpacity>

          <TouchableOpacity activeOpacity={0.8} onPress={onOpenDemo} style={styles.secondaryLink}>
            <Text style={styles.secondaryText}>
              See how the one-time license works <Text style={styles.secondaryArrow}>›</Text>
            </Text>
          </TouchableOpacity>
        </View>
      </ImageBackground>
    </View>
  );
}

const styles = StyleSheet.create({
  wrapper: {
    width: "100%",
    backgroundColor: "#000",
  },

  bg: {
    width: "100%",
    minHeight: Platform.OS === "web" ? "100vh" : 740,
    justifyContent: "flex-start",
  },

  overlay: {
    ...StyleSheet.absoluteFillObject,
    backgroundColor: "rgba(0,0,0,0.55)",
  },

  vignetteTop: {
    position: "absolute",
    left: 0,
    right: 0,
    top: 0,
    height: 180,
    backgroundColor: "rgba(0,0,0,0.65)",
  },

  vignetteBottom: {
    position: "absolute",
    left: 0,
    right: 0,
    bottom: 0,
    height: 220,
    backgroundColor: "rgba(0,0,0,0.70)",
  },

  topBar: {
    position: "relative",
    zIndex: 2,
    width: "100%",
    paddingTop: 22,
    paddingHorizontal: 22,
    flexDirection: "row",
    alignItems: "center",
    justifyContent: "space-between",
  },

  logoRow: {
    flexDirection: "row",
    alignItems: "center",
  },

  logo: {
    width: 220,
    height: 52,
  },

  langBtn: {
    flexDirection: "row",
    alignItems: "center",
    gap: 8,
    paddingVertical: 10,
    paddingHorizontal: 14,
    borderRadius: 10,
    borderWidth: 1,
    borderColor: "rgba(255,255,255,0.22)",
    backgroundColor: "rgba(0,0,0,0.20)",
  },

  langIcon: { color: "#fff", fontSize: 16 },
  langText: { color: "#fff", fontSize: 16, fontWeight: "600" },
  langCaret: { color: "rgba(255,255,255,0.85)", fontSize: 14, marginLeft: 2 },

  content: {
    position: "relative",
    zIndex: 2,
    width: "100%",
    maxWidth: 980,
    alignSelf: "center",
    paddingTop: 110,
    paddingBottom: 90,
    alignItems: "center",
    textAlign: "center",
  },

  kicker: {
    color: "rgba(255,255,255,0.92)",
    fontWeight: "500",
    marginBottom: 16,
    textAlign: "center",
  },

  headline: {
    color: "#fff",
    fontWeight: "800",
    letterSpacing: -0.8,
    textAlign: "center",
    lineHeight: 1.05 * 64, // web ignores, native uses number; acceptable as style
  },

  headlineAccent: {
    color: "#F09A2B",
  },

  sub: {
    marginTop: 16,
    color: "rgba(255,255,255,0.78)",
    maxWidth: 720,
    textAlign: "center",
    lineHeight: 26,
  },

  cta: {
    marginTop: 26,
    flexDirection: "row",
    alignItems: "center",
    justifyContent: "center",
    gap: 12,
    paddingVertical: 16,
    paddingHorizontal: 22,
    borderRadius: 12,
    backgroundColor: "#E07A15",
    borderWidth: 1,
    borderColor: "rgba(255,255,255,0.12)",
    shadowColor: "#000",
    shadowOpacity: 0.35,
    shadowRadius: 14,
    shadowOffset: { width: 0, height: 8 },
    elevation: 6,
    minWidth: 320,
  },

  playCircle: {
    width: 34,
    height: 34,
    borderRadius: 999,
    backgroundColor: "rgba(255,255,255,0.18)",
    alignItems: "center",
    justifyContent: "center",
  },

  playIcon: {
    color: "#fff",
    fontSize: 14,
    marginLeft: 2,
    fontWeight: "800",
  },

  ctaText: {
    color: "#fff",
    fontSize: 18,
    fontWeight: "800",
  },

  secondaryLink: {
    marginTop: 14,
  },

  secondaryText: {
    color: "rgba(255,255,255,0.78)",
    fontSize: 16,
    fontWeight: "500",
  },

  secondaryArrow: {
    color: "rgba(255,255,255,0.90)",
    fontSize: 18,
  },
});
